#include <stdio.h>
#include <stdint.h>
#include <inttypes.h>

static uint64_t gcd_uint64(uint64_t a, uint64_t b) {
    while (b) {
        uint64_t t = b;
        b = a % b;
        a = t;
    }
    return a;
}

uint64_t binom(uint64_t n, uint64_t k) {
    if (k > n) return 0;
    if (k > n - k) k = n - k;
    uint64_t result = 1;
    for (uint64_t i = 1; i <= k; ++i) {
        uint64_t num = n - k + i;
        uint64_t den = i;
        uint64_t g = gcd_uint64(num, den);
        num /= g; den /= g;
        g = gcd_uint64(result, den);
        result /= g; den /= g;
        __uint128_t tmp = ( __uint128_t)result * num;
        result = (uint64_t)tmp; // fits in 64 bits by problem guarantee
    }
    return result;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        unsigned long long N, K; scanf("%llu %llu", &N, &K);
        printf("%llu\n", binom(N, K));
    }
    return 0;
}

