#include <bits/stdc++.h>
using namespace std;

static unsigned long long gcd_ull(unsigned long long a, unsigned long long b) {
    while (b) { unsigned long long t = b; b = a % b; a = t; }
    return a;
}

unsigned long long binom(unsigned long long n, unsigned long long k) {
    if (k > n) return 0ULL;
    if (k > n - k) k = n - k;
    unsigned long long res = 1ULL;
    for (unsigned long long i = 1; i <= k; ++i) {
        unsigned long long num = n - k + i;
        unsigned long long den = i;
        unsigned long long g = gcd_ull(num, den);
        num /= g; den /= g;
        g = gcd_ull(res, den);
        res /= g; den /= g;
        __uint128_t tmp = ( __uint128_t)res * num;
        res = (unsigned long long)tmp; // fits by guarantee
    }
    return res;
}

