import java.io.*;
import java.util.*;
import java.math.BigInteger;

public class Main {
    private static long gcd(long a, long b) {
        while (b != 0) {
            long t = b;
            b = a % b;
            a = t;
        }
        return a;
    }

    private static BigInteger binom(BigInteger n, BigInteger k) {
        if (k.compareTo(n) > 0) return BigInteger.ZERO;
        BigInteger nk = n.subtract(k);
        if (k.compareTo(nk) > 0) k = nk; // k = min(k, n-k)
        BigInteger result = BigInteger.ONE;
        for (BigInteger i = BigInteger.ONE; i.compareTo(k) <= 0; i = i.add(BigInteger.ONE)) {
            BigInteger num = n.subtract(k).add(i);
            BigInteger den = i;
            long g = gcd(num.longValueExact(), den.longValueExact());
            num = num.divide(BigInteger.valueOf(g));
            den = den.divide(BigInteger.valueOf(g));
            g = gcd(result.longValueExact(), den.longValueExact());
            result = result.divide(BigInteger.valueOf(g));
            den = den.divide(BigInteger.valueOf(g));
            result = result.multiply(num);
        }
        return result;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; ++t) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            BigInteger N = new BigInteger(st.nextToken());
            BigInteger K = new BigInteger(st.nextToken());
            sb.append(binom(N, K).toString()).append('\n');
        }
        System.out.print(sb.toString());
    }
}

