function gcd(a, b) {
  while (b !== 0n) {
    const t = b;
    b = a % b;
    a = t;
  }
  return a;
}
function binom(n, k) {
  if (k > n) return 0n;
  if (k > n - k) k = n - k;
  let res = 1n;
  for (let i = 1n; i <= k; i++) {
    let num = n - k + i;
    let den = i;
    let g = gcd(num, den);
    num /= g; den /= g;
    g = gcd(res, den);
    res /= g; den /= g;
    res *= num; // result stays < 2^64, fits in BigInt
  }
  return res;
